  local.db.wp_posts['ID:60'] = {
    ID: 60,
    post_title: 'Independent post',
    post_content: 'Independent body',
    post_status: 'publish',
  };
  local.db.wp_posts['ID:61'] = {
    ID: 61,
    post_title: 'Local revision title',
    post_content: 'Local revision body',
    post_status: 'inherit',
    post_type: 'revision',
    post_parent: 60,
  };

  const remote = baseSite();
