  assert.equal(relationshipObjectReference.relationshipKey, 'wp_term_relationships.object_id');
  assert.equal(relationshipObjectReference.relationshipType, 'term-relationship-object');
  assert.equal(relationshipObjectReference.targetResourceKey, parentResourceKey);
  assert.equal(relationshipObjectReference.resolutionPolicy, 'same-plan-local-create');
  assert.equal(relationshipTaxonomyReference.relationshipKey, 'wp_term_relationships.term_taxonomy_id');
  assert.equal(relationshipTaxonomyReference.relationshipType, 'term-relationship-taxonomy');
  assert.equal(relationshipTaxonomyReference.targetResourceKey, taxonomyResourceKey);
  assert.equal(relationshipTaxonomyReference.resolutionPolicy, 'same-plan-local-create');
