  assert.equal(result.site.db.wp_posts['ID:10'].post_parent, 99);
  assert.equal(result.site.db.wp_posts['ID:10'].post_title, 'Local child post');
  assert.equal(result.site.db.wp_postmeta['meta_id:55'].post_id, 99);
