test('blocks a file type swap that would hide a live remote descendant while preserving remote-only plugin drift', () => {
  const base = baseSite();
  base.files['wp-content/uploads/gallery'] = 'base gallery file';
  base.files['wp-content/uploads/gallery/keep.txt'] = 'base descendant bytes';

  const local = baseSite();
  local.files['wp-content/uploads/gallery'] = { type: 'directory' };
  delete local.files['wp-content/uploads/gallery/keep.txt'];
  local.files['about.php'] = '<?php echo "shared about";';

  const remote = JSON.parse(JSON.stringify(base));
  remote.files['wp-content/uploads/gallery/keep.txt'] = 'remote descendant bytes';
  remote.files['about.php'] = '<?php echo "shared about";';
  remote.plugins.forms.description = 'remote-only plugin drift';
  remote.files['wp-content/plugins/forms/forms.php'] = '<?php /* remote-only plugin drift */';

  const plan = planFor(base, local, remote);
  const evidence = plan.conflicts[0] || plan.blockers[0];
  const evidenceJson = JSON.stringify(evidence);

  assert.equal(plan.status, 'conflict');
  assert.equal(plan.summary.mutations >= 0, true);
  assert.equal(plan.summary.blockers + plan.summary.conflicts > 0, true);
  assert.equal(mutationFor(plan, 'file:wp-content/uploads/gallery').action, 'put');
  assert.equal(mutationFor(plan, 'file:wp-content/uploads/gallery').changeKind, 'type-change');
  assert.equal(decisionFor(plan, 'file:about.php').decision, 'already-in-sync');
  assert.equal(decisionFor(plan, 'plugin:forms').decision, 'keep-remote');
  assert.equal(decisionFor(plan, 'file:wp-content/plugins/forms/forms.php').decision, 'keep-remote');
  assert.equal(evidence.class, 'file-conflict');
  assert.equal(evidence.resourceKey, 'file:wp-content/uploads/gallery/keep.txt');
  assert.equal(evidenceJson.includes('base descendant bytes'), false);
  assert.equal(evidenceJson.includes('remote descendant bytes'), false);
  assert.equal(evidenceJson.includes('remote-only plugin drift'), false);
  assert.throws(() => applyPlan(remote, plan), /Refusing to apply/);
  assert.equal(remote.plugins.forms.description, 'remote-only plugin drift');
});

test('blocks local post-parent references to a same-plan created attachment identity while preserving a matching independent edit and remote-only plugin changes', () => {
  const resourceKey = 'row:["wp_posts","ID:10"]';
  const targetResourceKey = 'row:["wp_posts","ID:8"]';
  const base = baseSite();
  base.db.wp_posts['ID:1'].post_title = 'Base shared post title';

  const local = baseSite();
  local.db.wp_posts['ID:1'].post_title = 'Shared post title';
  local.db.wp_posts['ID:8'] = {
    ID: 8,
    post_title: 'local-created attachment target',
    post_content: 'local-created attachment body',
    post_type: 'attachment',
    post_status: 'inherit',
  };
  local.db.wp_posts['ID:10'] = {
    ID: 10,
    post_title: 'local-private-child-post',
    post_content: 'local-private-child-body',
    post_status: 'publish',
    post_parent: 8,
  };

  const remote = baseSite();
  remote.db.wp_posts['ID:1'].post_title = 'Shared post title';
  remote.plugins.forms.description = 'remote-only plugin change';
  remote.files['wp-content/plugins/forms/forms.php'] = '<?php /* remote-only plugin change */';

  const plan = planFor(base, local, remote);
  const blocker = plan.blockers.find((entry) => entry.class === 'unsupported-attachment-resource' && entry.resourceKey === targetResourceKey);
  const matchingEdit = decisionFor(plan, 'row:["wp_posts","ID:1"]');
  const pluginDecision = decisionFor(plan, 'plugin:forms');
  const pluginFileDecision = decisionFor(plan, 'file:wp-content/plugins/forms/forms.php');
  const planJson = JSON.stringify(plan);

  assert.equal(plan.status, 'blocked');
  assert.equal(plan.summary.mutations, 0);
  assert.equal(mutationFor(plan, resourceKey), undefined);
  assert.equal(decisionFor(plan, targetResourceKey), undefined);
  assert.equal(blocker.class, 'unsupported-attachment-resource');
  assert.equal(blocker.resourceKey, targetResourceKey);
  assert.equal(
    blocker.reason,
    'WordPress graph mutation row:["wp_posts","ID:8"] is created in the same plan as a post parent attachment target that depends on it, and identity rewriting is not yet supported.',
  );
  assert.equal(matchingEdit.decision, 'already-in-sync');
  assert.equal(matchingEdit.change.localChange, 'update');
  assert.equal(matchingEdit.change.remoteChange, 'update');
  assert.equal(pluginDecision.decision, 'keep-remote');
  assert.equal(pluginFileDecision.decision, 'keep-remote');
  assert.equal(planJson.includes('local-created attachment target'), false);
  assert.equal(planJson.includes('local-created attachment body'), false);
  assert.equal(planJson.includes('local-private-child-post'), false);
  assert.equal(planJson.includes('local-private-child-body'), false);
  assert.equal(planJson.includes('remote-only plugin change'), false);
  assert.equal(remote.plugins.forms.description, 'remote-only plugin change');
  assert.equal(remote.files['wp-content/plugins/forms/forms.php'], '<?php /* remote-only plugin change */');
});

